class Solution {
    public int smallestValue(int n) {
        int minVal = n;
        int current = n;
        while (true) {
            int sum = getSumPrimeFactors(current);
            if (sum == current) {
                break;
            }
            if (sum < minVal) {
                minVal = sum;
            }
            current = sum;
        }
        return minVal;
    }

    private int getSumPrimeFactors(int m) {
        int sum = 0;
        int current = m;
        for (int i = 2; i * i <= current; i++) {
            while (current % i == 0) {
                sum += i;
                current /= i;
            }
        }
        if (current > 1) {
            sum += current;
        }
        return sum;
    }
}

